let cmd = (msg.command ?? msg._cmd ?? msg.payload ?? "")
  .toString()
  .trim();

// ------------------------------
// FIX: commandes qui arrivent avec guillemets
// ex: '"PBATMAXDISC150"' ou 'PBATMAXDISC150""'
// ------------------------------

// si c'est du JSON stringifié (ex: "\"PBATMAXDISC150\""), tente parse
try {
  if (cmd.startsWith('"') || cmd.startsWith('\\"')) {
    const parsed = JSON.parse(cmd);
    if (typeof parsed === "string") cmd = parsed;
  }
} catch (e) {
  // ignore
}

// retire guillemets parasites au début/fin
cmd = cmd.trim().replace(/^"+|"+$/g, "");

// upper après nettoyage
cmd = cmd.toUpperCase();

if (!cmd) {
  node.warn("Commande vide -> ignorée");
  return null;
}

/*
  Validation "safe" :
  - Requêtes classiques: QPIGS, QPIRI, QMOD, QET, QLD20260220, etc.
  - SET Voltronic: souvent Pxxxx + valeur (ex: PCVV55.7, PBT02, PBATMAXDISC150, etc.)
  On autorise uniquement: A-Z / 0-9 / '.' / '-' et on contrôle les patterns.
*/
const isQueryOrStat =
  /^[A-Z]{2,6}[0-9]*$/.test(cmd); // ex: QPIGS, QPIRI, QET, QED20260220, QEY2026...

const isSetWithValue =
  /^P[A-Z0-9]{2,12}-?[0-9]+(\.[0-9]+)?$/.test(cmd);
// ↑ élargi à 2..12 (PBATMAXDISC = 10 lettres après P)

// IMPORTANT: PBATMAXDISC est un SET spécial avec 3 digits, ex: PBATMAXDISC150
// Il match déjà la regex ci-dessus, mais on garde ce commentaire pour clarté.

if (!isQueryOrStat && !isSetWithValue) {
  node.warn(`Commande invalide ignorée: "${cmd}"`);
  return null;
}

// Conserver la commande envoyée (utile pour associer RX)
msg.command = cmd;
msg._cmd = cmd;

// Construire la trame (CRC + CR)
let buf;
try {
  buf = helpers.buildVoltronicCommand(cmd);
} catch (e) {
  node.error(`Erreur buildVoltronicCommand("${cmd}") : ${e.message || e}`);
  return null;
}

// Payload = Buffer à envoyer dans Serial Out
msg.payload = buf;

// Debug utile
msg._tx_ts = Date.now();
msg._tx_ascii = cmd;
msg._tx_hex = buf.toString("hex");

// Status (optionnel)
node.status({
  fill: "blue",
  shape: "dot",
  text: `${cmd} → ond${msg.inverterNum ?? "?"}`
});

// Mémorise la dernière commande par onduleur (utile RX/timeout)
if (msg.inverterNum != null) {
  flow.set(`inv${msg.inverterNum}_last_cmd`, msg._cmd);
  flow.set(`inv${msg.inverterNum}_last_cmd_ts`, Date.now());
}

return msg;

// ====== REQUETES (Option A + firstRun + force + OPTIONAL CMD AUTO-DISABLE + retry 1h + DIAG) ======
// - Boot burst prioritaire
// - Polling temps réel léger
// - Auto-disable après 3 échecs pour commandes optionnelles
// - Retest 1 fois/heure si désactivée
// - Si une commande redevient OK, le parser / timeout logic doit remettre disabled=false + fail_count=0

const inverterNum = 3;
const ts = Date.now();
const now = new Date();

const pad2 = (n) => String(n).padStart(2, "0");
const yyyy = now.getFullYear();
const mm = pad2(now.getMonth() + 1);
const dd = pad2(now.getDate());

const yyyymm = `${yyyy}${mm}`;
const yyyymmdd = `${yyyy}${mm}${dd}`;

const RETRY_MS = 60 * 60 * 1000; // 1h

// --------------------------------------------------
// helpers messages
// --------------------------------------------------
function makeCmd(cmd, extra = {}) {
  return {
    inverterNum,
    command: cmd,
    _cmd: cmd,
    payload: cmd,
    ...extra
  };
}

// --------------------------------------------------
// helpers états optionnels génériques
// --------------------------------------------------
function getCmdState(cmd) {
  const key = `inv${inverterNum}_cmd_state_${cmd}`;
  let st = flow.get(key);

  if (!st || typeof st !== "object") {
    st = {
      fail_count: 0,
      disabled: false,
      last_try: 0,
      last_ok: 0,
      last_fail: 0,
      reason: ""
    };
    flow.set(key, st);
  }

  return st;
}

function setCmdState(cmd, st) {
  flow.set(`inv${inverterNum}_cmd_state_${cmd}`, st);
}

function shouldTryCmdNow(cmd) {
  const st = getCmdState(cmd);

  // actif normal
  if (!st.disabled) return true;

  // désactivé => 1 essai max/heure
  return (ts - Number(st.last_try || 0)) >= RETRY_MS;
}

function markCmdScheduled(cmd, reason) {
  const st = getCmdState(cmd);
  st.last_try = ts;
  if (reason) st.reason = reason;
  setCmdState(cmd, st);
}

function isCmdDisabled(cmd) {
  return !!getCmdState(cmd).disabled;
}

function addOptionalCmd(msgs, cmd, reasonIfScheduled = "normal", extra = {}) {
  if (shouldTryCmdNow(cmd)) {
    msgs.push(makeCmd(cmd, extra));
    markCmdScheduled(cmd, reasonIfScheduled);
    return true;
  }
  return false;
}

function addOptionalCmdWithArg(msgs, fullCmd, baseCmd, reasonIfScheduled = "normal", extra = {}) {
  if (shouldTryCmdNow(baseCmd)) {
    msgs.push(makeCmd(fullCmd, extra));
    markCmdScheduled(baseCmd, reasonIfScheduled);
    return true;
  }
  return false;
}

// --------------------------------------------------
// liste des commandes optionnelles surveillées
// --------------------------------------------------
const OPTIONAL_BASE_CMDS = [
  "QPIGS2",
  "QED", "QEM", "QEY", "QET",
  "QLD", "QLM", "QLY", "QLT"
];

// --------------------------------------------------
// état local
// --------------------------------------------------
let alt = context.get("alt");
if (alt === undefined || alt === null) alt = 0;

let firstRun = context.get("firstRun");
if (firstRun === undefined) firstRun = true;

// force burst
if (msg && msg.forceFirstRun === true) {
  firstRun = true;
}

// timers
let nextQMOD = context.get("nextQMOD");
let nextHour = context.get("nextHour");
let nextDay10m = context.get("nextDay10m");
let nextMonth6 = context.get("nextMonth6");
let nextYear24 = context.get("nextYear24");
let nextQPIRI = context.get("nextQPIRI");
let nextQDOP = context.get("nextQDOP");
let nextQPIWS = context.get("nextQPIWS");

const msgs = [];

// --------------------------------------------------
// helpers status
// --------------------------------------------------
function countDisabledOptional() {
  let count = 0;
  for (const c of OPTIONAL_BASE_CMDS) {
    if (isCmdDisabled(c)) count++;
  }
  return count;
}

function optionalSummaryText() {
  const disabled = OPTIONAL_BASE_CMDS.filter(c => isCmdDisabled(c));
  if (!disabled.length) return "all optional cmds enabled";
  return `disabled: ${disabled.join(", ")}`;
}

// --------------------------------------------------
// realtime tick
// --------------------------------------------------
function pushRealtimeTick() {
  const qpigs2Disabled = isCmdDisabled("QPIGS2");

  if (!qpigs2Disabled) {
    // mode normal: alternance QPIGS / QPIGS2
    if (alt === 0) {
      msgs.push(makeCmd("QPIGS"));
      alt = 1;
    } else {
      addOptionalCmd(msgs, "QPIGS2", "normal", { _qpigs2_probe: false });
      alt = 0;
    }
    return;
  }

  // QPIGS2 désactivé => QPIGS seul + 1 retest/heure
  msgs.push(makeCmd("QPIGS"));

  addOptionalCmd(msgs, "QPIGS2", "hourly_retry", { _qpigs2_probe: true });
}

// =========================
// 1) BOOT BURST
// =========================
if (firstRun) {
  // paramètres fixes
  msgs.push(makeCmd("QPIRI"));
  msgs.push(makeCmd("QDOP"));

  // état rapide
  msgs.push(makeCmd("QMOD"));

  // énergies PV
  addOptionalCmd(msgs, "QET", "boot");
  addOptionalCmdWithArg(msgs, `QEY${yyyy}`, "QEY", "boot");
  addOptionalCmdWithArg(msgs, `QEM${yyyymm}`, "QEM", "boot");
  addOptionalCmdWithArg(msgs, `QED${yyyymmdd}`, "QED", "boot");

  // énergies LOAD
  addOptionalCmd(msgs, "QLT", "boot");
  addOptionalCmdWithArg(msgs, `QLY${yyyy}`, "QLY", "boot");
  addOptionalCmdWithArg(msgs, `QLM${yyyymm}`, "QLM", "boot");
  addOptionalCmdWithArg(msgs, `QLD${yyyymmdd}`, "QLD", "boot");

  // diag boot
  msgs.push(makeCmd("QMN"));
  msgs.push(makeCmd("QID"));
  msgs.push(makeCmd("QVFW"));
  msgs.push(makeCmd("QVFW3"));
  msgs.push(makeCmd("QPIWS"));

  // boot realtime
  msgs.push(makeCmd("QPIGS"));
  addOptionalCmd(msgs, "QPIGS2", "boot", { _qpigs2_probe: isCmdDisabled("QPIGS2") === true });

  // schedules
  nextQMOD = ts + 5 * 60 * 1000;
  nextHour = ts + 60 * 60 * 1000;
  nextDay10m = ts + 10 * 60 * 1000;
  nextMonth6 = ts + 6 * 60 * 60 * 1000;
  nextYear24 = ts + 24 * 60 * 60 * 1000;
  nextQPIRI = ts + 5 * 60 * 1000;
  nextQDOP = ts + 5 * 60 * 1000;
  nextQPIWS = ts + 5 * 60 * 1000;

  firstRun = false;

  node.status({
    fill: countDisabledOptional() > 0 ? "yellow" : "green",
    shape: "dot",
    text: `FIRST RUN: ${msgs.length} cmds | ${optionalSummaryText()}`
  });
}

// =========================
// 2) NORMAL MODE
// =========================
else {
  // QMOD 5 min
  if (nextQMOD == null) nextQMOD = ts + 5 * 60 * 1000;
  if (ts >= nextQMOD) {
    msgs.push(makeCmd("QMOD"));
    nextQMOD = ts + 5 * 60 * 1000;
  }

  // QPIRI 5 min
  if (nextQPIRI == null) nextQPIRI = ts + 5 * 60 * 1000;
  if (ts >= nextQPIRI) {
    msgs.push(makeCmd("QPIRI"));
    nextQPIRI = ts + 5 * 60 * 1000;
  }

  // QDOP 5 min
  if (nextQDOP == null) nextQDOP = ts + 5 * 60 * 1000;
  if (ts >= nextQDOP) {
    msgs.push(makeCmd("QDOP"));
    nextQDOP = ts + 5 * 60 * 1000;
  }

  // QPIWS 5 min
  if (nextQPIWS == null) nextQPIWS = ts + 5 * 60 * 1000;
  if (ts >= nextQPIWS) {
    msgs.push(makeCmd("QPIWS"));
    nextQPIWS = ts + 5 * 60 * 1000;
  }

  // hourly
  if (nextHour == null) nextHour = ts + 60 * 60 * 1000;
  if (ts >= nextHour) {
    // total PV / LOAD
    addOptionalCmd(msgs, "QET", "hourly_retry");
    addOptionalCmd(msgs, "QLT", "hourly_retry");

    // diag hourly
    msgs.push(makeCmd("QMN"));
    msgs.push(makeCmd("QID"));
    msgs.push(makeCmd("QVFW"));
    msgs.push(makeCmd("QVFW3"));

    nextHour = ts + 60 * 60 * 1000;
  }

  // daily 10 min
  if (nextDay10m == null) nextDay10m = ts + 10 * 60 * 1000;
  if (ts >= nextDay10m) {
    addOptionalCmdWithArg(msgs, `QED${yyyymmdd}`, "QED", "scheduled_retry");
    addOptionalCmdWithArg(msgs, `QLD${yyyymmdd}`, "QLD", "scheduled_retry");
    nextDay10m = ts + 10 * 60 * 1000;
  }

  // monthly 6h
  if (nextMonth6 == null) nextMonth6 = ts + 6 * 60 * 60 * 1000;
  if (ts >= nextMonth6) {
    addOptionalCmdWithArg(msgs, `QEM${yyyymm}`, "QEM", "scheduled_retry");
    addOptionalCmdWithArg(msgs, `QLM${yyyymm}`, "QLM", "scheduled_retry");
    nextMonth6 = ts + 6 * 60 * 60 * 1000;
  }

  // yearly 24h
  if (nextYear24 == null) nextYear24 = ts + 24 * 60 * 60 * 1000;
  if (ts >= nextYear24) {
    addOptionalCmdWithArg(msgs, `QEY${yyyy}`, "QEY", "scheduled_retry");
    addOptionalCmdWithArg(msgs, `QLY${yyyy}`, "QLY", "scheduled_retry");
    nextYear24 = ts + 24 * 60 * 60 * 1000;
  }

  // realtime toujours à la fin
  pushRealtimeTick();

  node.status({
    fill: countDisabledOptional() > 0 ? "yellow" : "green",
    shape: "dot",
    text: `${msgs.length} cmds | ${optionalSummaryText()}`
  });
}

// --------------------------------------------------
// save context
// --------------------------------------------------
context.set("alt", alt);
context.set("firstRun", firstRun);
context.set("nextQMOD", nextQMOD);
context.set("nextHour", nextHour);
context.set("nextDay10m", nextDay10m);
context.set("nextMonth6", nextMonth6);
context.set("nextYear24", nextYear24);
context.set("nextQPIRI", nextQPIRI);
context.set("nextQDOP", nextQDOP);
context.set("nextQPIWS", nextQPIWS);

return [msgs];

// ====== PARSER 1 (Voltronic) - QUEUE MODE + LEARNING + VERIFY + QPIGS2 + RAW TEST ======
// Entrée: msg.payload = Buffer
// Sorties:
//   1) contrôle queue (retry learn / verify / pump)
//   2) data parsée + publication raw_response/raw_last_command

const inv = msg.inverterNum ?? 1;
if (!Buffer.isBuffer(msg.payload)) return null;

// --------------------------------------------------
// accumulateur RX
// --------------------------------------------------
let rx = context.get("rxbuf");
if (!Buffer.isBuffer(rx)) rx = Buffer.alloc(0);

// sécurité overflow
if (rx.length > 8192) rx = Buffer.alloc(0);

// concat
rx = Buffer.concat([rx, msg.payload]);

const CR = 0x0D;

// extrait toutes les frames finissant par CR
const frames = [];
while (true) {
  const idx = rx.indexOf(CR);
  if (idx === -1) break;
  frames.push(rx.slice(0, idx + 1));
  rx = rx.slice(idx + 1);
}
context.set("rxbuf", rx);

if (!frames.length) return null;

// --------------------------------------------------
// inflight
// --------------------------------------------------
const inflightKey = `inv${inv}_inflight`;
const inflight = flow.get(inflightKey);
const inflightCmd = inflight?.cmd || "UNKNOWN";

// pending learn
const pendingLearnKey = `learn_pending_inv${inv}`;
let pendingLearn = flow.get(pendingLearnKey);

// --------------------------------------------------
// helpers
// --------------------------------------------------
function pad2(x) {
  return String(Math.trunc(Number(x))).padStart(2, "0");
}
function pad3(x) {
  return String(Math.trunc(Number(x))).padStart(3, "0");
}
function fixed1(x) {
  return Number(x).toFixed(1);
}
function clamp(x, a, b) {
  return Math.min(b, Math.max(a, Number(x)));
}
function uniq(arr) {
  return [...new Set((arr || []).filter(Boolean))];
}
function toNum(v) {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
}
function s(v) {
  return String(v ?? "").trim();
}
function upper(v) {
  return s(v).toUpperCase();
}

// machine id parallèle
let machine = flow.get(`inv${inv}_parallel_id`);
if (machine === undefined || machine === null || machine === "") machine = 0;
machine = Number(machine);
if (!Number.isFinite(machine) || machine < 0 || machine > 9) machine = 0;

// --------------------------------------------------
// optional command state helpers (generic)
// --------------------------------------------------
function baseCmd(cmd) {
  const x = upper(cmd);

  if (x.startsWith("QED")) return "QED";
  if (x.startsWith("QEM")) return "QEM";
  if (x.startsWith("QEY")) return "QEY";
  if (x === "QET") return "QET";

  if (x.startsWith("QLD")) return "QLD";
  if (x.startsWith("QLM")) return "QLM";
  if (x.startsWith("QLY")) return "QLY";
  if (x === "QLT") return "QLT";

  if (x === "QPIGS2") return "QPIGS2";

  return x;
}

function isOptionalMonitoredCmd(cmd) {
  const b = baseCmd(cmd);
  return [
    "QPIGS2",
    "QED", "QEM", "QEY", "QET",
    "QLD", "QLM", "QLY", "QLT"
  ].includes(b);
}

function getCmdState(cmd) {
  const b = baseCmd(cmd);
  const key = `inv${inv}_cmd_state_${b}`;
  let st = flow.get(key);

  if (!st || typeof st !== "object") {
    st = {
      fail_count: 0,
      disabled: false,
      last_try: 0,
      last_ok: 0,
      last_fail: 0,
      reason: ""
    };
    flow.set(key, st);
  }

  return st;
}

function setCmdState(cmd, st) {
  const b = baseCmd(cmd);
  flow.set(`inv${inv}_cmd_state_${b}`, st);
}

function markCmdOk(cmd) {
  const st = getCmdState(cmd);
  st.fail_count = 0;
  st.disabled = false;
  st.last_ok = Date.now();
  st.reason = "ok";
  setCmdState(cmd, st);
  return st;
}

function markCmdFail(cmd, reason) {
  const st = getCmdState(cmd);
  st.fail_count = Number(st.fail_count || 0) + 1;
  st.last_fail = Date.now();
  st.reason = reason || "fail";
  if (st.fail_count >= 3) st.disabled = true;
  setCmdState(cmd, st);
  return st;
}

function isSuccessfulParsedResponse(p) {
  if (!p) return false;
  if (p.nak === true) return false;
  if (p.ack === true) return true;
  return typeof p.raw === "string" && p.raw.trim() !== "" && p.raw !== "NAK";
}

// --------------------------------------------------
// variantes apprentissage simples
// --------------------------------------------------
const simpleVariants = {
  battery_bulk_voltage: [
    {
      label: "PCVV",
      build: (nv) => `PCVV${fixed1(nv)}`
    },
    {
      label: "CVVV",
      build: (nv) => `CVVV${fixed1(nv)}`
    }
  ],

  battery_float_voltage: [
    {
      label: "PBFT",
      build: (nv) => `PBFT${fixed1(nv)}`
    }
  ],

  max_charging_current: [
    {
      label: "MNCHGC_machine",
      build: (nv) => `MNCHGC${machine}${pad3(clamp(nv, 0, 200))}`
    },
    {
      label: "MNCHGC_plain",
      build: (nv) => `MNCHGC${pad3(clamp(nv, 0, 200))}`
    }
  ],

  max_ac_charging_current: [
    {
      label: "MUCHGC_machine",
      build: (nv) => `MUCHGC${machine}${pad3(clamp(nv, 0, 200))}`
    },
    {
      label: "MUCHGC_plain",
      build: (nv) => `MUCHGC${pad3(clamp(nv, 0, 200))}`
    }
  ]
};

// --------------------------------------------------
// nettoyage trame -> ASCII sans CRC/CR
// --------------------------------------------------
function cleanAsciiFromFrame(frameBuf) {
  if (frameBuf.length === 1 && frameBuf[0] === 0x15) return "NAK";
  if (frameBuf.length === 1 && frameBuf[0] === 0x06) return "ACK";

  let dataBuf = frameBuf;

  if (frameBuf.length >= 3 && frameBuf[frameBuf.length - 1] === CR) {
    dataBuf = frameBuf.slice(0, -3);
  } else if (frameBuf.length >= 1 && frameBuf[frameBuf.length - 1] === CR) {
    dataBuf = frameBuf.slice(0, -1);
  }

  return dataBuf.toString("ascii");
}

// --------------------------------------------------
// decode priority helpers
// --------------------------------------------------
function decodeOutputSourcePriority(codeRaw) {
  const code = s(codeRaw);

  const map = {
    "0": "UtilitySolarBat",
    "00": "UtilitySolarBat",
    "1": "SolarUtilityBat",
    "01": "SolarUtilityBat",
    "2": "SolarBatUtility",
    "02": "SolarBatUtility"
  };

  return map[code] || null;
}

function decodeChargerSourcePriority(codeRaw) {
  const code = s(codeRaw);

  const map = {
    "0": "Solar first",
    "00": "Solar first",
    "1": "Solar + Utility",
    "01": "Solar + Utility",
    "2": "Only solar",
    "02": "Only solar"
  };

  return map[code] || null;
}

function decodeBatteryType(codeRaw) {
  const code = s(codeRaw);

  const map = {
    "0": "AGM",
    "00": "AGM",
    "1": "Flooded",
    "01": "Flooded",
    "2": "User",
    "02": "User",
    "3": "Pylon",
    "03": "Pylon",
    "5": "Weco",
    "05": "Weco",
    "6": "Soltaro",
    "06": "Soltaro",
    "8": "Lib",
    "08": "Lib",
    "9": "Lic",
    "09": "Lic"
  };

  return map[code] || null;
}

// --------------------------------------------------
// decode QPIRI / QDI
// --------------------------------------------------
function decodeStateFields(cmd, fields) {
  const c = upper(cmd);
  const state = {};

  // Sur beaucoup de firmwares Voltronic, QPIRI et QDI exposent :
  // [12]=battery_type
  // [13]=max_ac_charging_current
  // [14]=max_charging_current
  // [15]=input_voltage_range
  // [16]=output_source_priority
  // [17]=charger_source_priority
  // [22]=battery_redischarge_voltage
  //
  // On garde ça ici car c'est précisément ce qu'il faut pour ton apprentissage.
  if ((c === "QPIRI" || c === "QDI") && fields.length >= 18) {
    state.battery_type_code = fields[12] ?? null;
    state.battery_type = decodeBatteryType(fields[12]);

    state.max_ac_charging_current = toNum(fields[13]);
    state.max_charging_current = toNum(fields[14]);

    state.input_voltage_range_code = fields[15] ?? null;

    state.output_source_priority_code = fields[16] ?? null;
    state.output_source_priority = decodeOutputSourcePriority(fields[16]);

    state.charger_source_priority_code = fields[17] ?? null;
    state.charger_source_priority = decodeChargerSourcePriority(fields[17]);

    if (fields.length > 22) {
      state.battery_re_discharge_voltage = toNum(fields[22]);
    }
  }

  return state;
}

// --------------------------------------------------
// parse 1 frame
// --------------------------------------------------
function parseFrame(frameBuf, cmd) {
  const ascii = cleanAsciiFromFrame(frameBuf);

  if (ascii === "NAK" || ascii.includes("NAK")) {
    return {
      inverter: inv,
      command: cmd,
      nak: true,
      ack: false,
      raw: "NAK",
      fields: [],
      nums: [],
      value: null,
      state: {}
    };
  }

  if (ascii === "ACK" || ascii.includes("ACK")) {
    return {
      inverter: inv,
      command: cmd,
      ack: true,
      nak: false,
      raw: "ACK",
      fields: [],
      nums: [],
      value: null,
      state: {}
    };
  }

  let body = ascii.trim();
  if (body.startsWith("(")) body = body.slice(1);
  if (body.endsWith(")")) body = body.slice(0, -1);
  body = body.trim();

  const fields = body.length ? body.split(/\s+/) : [];
  const nums = fields.map(v => {
    const n = Number(v);
    return Number.isFinite(n) ? n : null;
  });

  const isEnergyCmd = /^Q(E[TYMD]|L[TYMD])/.test(upper(cmd));
  let value = null;
  if (isEnergyCmd && fields.length >= 1) {
    const n0 = Number(fields[0]);
    if (Number.isFinite(n0)) value = n0;
  }

  const state = decodeStateFields(cmd, fields);

  return {
    inverter: inv,
    command: cmd,
    raw: body,
    fields,
    nums,
    value,
    state,
    ack: false,
    nak: false
  };
}

// --------------------------------------------------
// parse toutes les frames
// --------------------------------------------------
const outMsgs = [];
let firstParsed = null;

for (let i = 0; i < frames.length; i++) {
  const cmd = (i === 0) ? inflightCmd : "UNKNOWN";
  const parsed = parseFrame(frames[i], cmd);

  if (i === 0) firstParsed = parsed;

  outMsgs.push({
    inverterNum: inv,
    _cmd: cmd,
    command: cmd,
    payload: parsed,
    _rx_ts: Date.now()
  });
}

// --------------------------------------------------
// RAW TEST publication
// --------------------------------------------------
if (firstParsed && inflight && inflight._origin === "raw_test") {
  const rawResp =
    firstParsed.ack === true ? "ACK" :
    firstParsed.nak === true ? "NAK" :
    (firstParsed.raw || "");

  outMsgs.push({
    topic: `voltronic/${inv}/raw_response`,
    payload: rawResp
  });

  outMsgs.push({
    topic: `voltronic/${inv}/raw_last_command`,
    payload: inflightCmd
  });

  node.status({
    fill: "blue",
    shape: "dot",
    text: `RAW ${inflightCmd} => ${rawResp || "?"}`
  });
}

// --------------------------------------------------
// gestion commandes optionnelles monitorées
// --------------------------------------------------
if (firstParsed && isOptionalMonitoredCmd(inflightCmd)) {
  const bcmd = baseCmd(inflightCmd);

  if (firstParsed.nak === true) {
    const st = markCmdFail(inflightCmd, "nak");
    node.status({
      fill: st.disabled ? "red" : "yellow",
      shape: st.disabled ? "ring" : "dot",
      text: st.disabled
        ? `${bcmd} disabled (NAK ${st.fail_count}/3)`
        : `${bcmd} NAK (${st.fail_count}/3)`
    });
  } else if (isSuccessfulParsedResponse(firstParsed)) {
    markCmdOk(inflightCmd);
    node.status({
      fill: "green",
      shape: "dot",
      text: `${bcmd} OK`
    });
  }
}

// --------------------------------------------------
// Helpers learning
// --------------------------------------------------
function getLearnedStore() {
  let learned = global.get(`inverter_${inv}.learned_cmds`);
  if (!learned || typeof learned !== "object") learned = {};
  return learned;
}

function saveLearnedStore(learned) {
  global.set(`inverter_${inv}.learned_cmds`, learned);
}

function clearPendingLearn() {
  flow.set(pendingLearnKey, null);
}

function setPendingLearn(data) {
  flow.set(pendingLearnKey, {
    inverterNum: inv,
    ts: Date.now(),
    ...data
  });
}

function buildRetryMsg(nextCmd, learnObj, origin = "learn_retry") {
  return {
    inverterNum: inv,
    command: nextCmd,
    _cmd: nextCmd,
    payload: nextCmd,
    _burst: false,
    _origin: origin,
    _learn: learnObj
  };
}

function buildVerifyMsg(cmd = "QPIRI") {
  return {
    inverterNum: inv,
    command: cmd,
    _cmd: cmd,
    payload: cmd,
    _burst: false,
    _origin: "learn_verify"
  };
}

function advanceToNextCandidate(pending) {
  const list = Array.isArray(pending?.candidates) ? pending.candidates : [];
  const nextIndex = Number(pending?.candidate_index || 0) + 1;

  if (nextIndex >= list.length) {
    clearPendingLearn();
    node.status({
      fill: "red",
      shape: "ring",
      text: `LEARN FAIL ${pending?.param || "unknown"}`
    });
    return null;
  }

  const nextCmd = list[nextIndex];
  if (!nextCmd) {
    clearPendingLearn();
    node.status({
      fill: "red",
      shape: "ring",
      text: `LEARN FAIL ${pending?.param || "unknown"}`
    });
    return null;
  }

  setPendingLearn({
    ...pending,
    phase: "write",
    candidate_index: nextIndex,
    cmd: nextCmd
  });

  node.status({
    fill: "yellow",
    shape: "dot",
    text: `LEARN RETRY ${pending.param} -> ${nextCmd} (${nextIndex + 1}/${list.length})`
  });

  return buildRetryMsg(nextCmd, {
    active: true,
    param: pending.param,
    value: pending.value,
    family: pending.family,
    candidates: list,
    candidate_index: nextIndex,
    total_candidates: list.length,
    verify_required: !!pending.verify_required
  });
}

function saveSimpleLearn(pending) {
  const learned = getLearnedStore();
  const list = Array.isArray(pending?.candidates) ? pending.candidates : [];
  const idx = Number(pending?.candidate_index || 0);
  const chosenCmd = pending?.cmd || list[idx] || null;

  let label = null;
  const paramVariants = simpleVariants[pending.param] || [];
  for (const variant of paramVariants) {
    const maybe = variant.build(pending.value);
    if (maybe === chosenCmd) {
      label = variant.label;
      break;
    }
  }

  if (!label && pending.label) label = pending.label;

  learned[pending.param] = {
    label,
    verified: true,
    updated_at: Date.now()
  };

  saveLearnedStore(learned);
  clearPendingLearn();

  node.status({
    fill: "green",
    shape: "dot",
    text: `LEARN OK ${pending.param}=${label || chosenCmd}`
  });
}

function saveMappedLearn(pending, verifiedCmd) {
  const learned = getLearnedStore();

  if (!learned[pending.param] || typeof learned[pending.param] !== "object") {
    learned[pending.param] = {};
  }
  if (!learned[pending.param].map || typeof learned[pending.param].map !== "object") {
    learned[pending.param].map = {};
  }

  learned[pending.param].map[pending.value] = verifiedCmd;
  learned[pending.param].verified = true;
  learned[pending.param].updated_at = Date.now();

  saveLearnedStore(learned);
  clearPendingLearn();

  node.status({
    fill: "green",
    shape: "dot",
    text: `LEARN MAP ${pending.param} ${pending.value} -> ${verifiedCmd}`
  });
}

// --------------------------------------------------
// Vérification PCP / POP - STRICTE
// --------------------------------------------------
function expectedValueMatchesReadback(pending, parsed) {
  if (!pending || !parsed || !parsed.state) return false;

  if (pending.param === "output_source_priority") {
    return parsed.state.output_source_priority === pending.value;
  }

  if (pending.param === "charger_source_priority") {
    return parsed.state.charger_source_priority === pending.value;
  }

  return false;
}

function extractVerifiedCommandFromReadback(pending, parsed) {
  if (!pending || !parsed || parsed.ack || parsed.nak) return null;

  const currentCmd = upper(pending.cmd);

  if (!expectedValueMatchesReadback(pending, parsed)) {
    return null;
  }

  return currentCmd || null;
}

// --------------------------------------------------
// learning logic
// --------------------------------------------------
let retryMsg = null;
let verifyMsg = null;

if (firstParsed && pendingLearn) {
  const sameCmd = pendingLearn.cmd === inflightCmd;
  const phase = pendingLearn.phase || "write";

  // --------------------
  // PHASE WRITE
  // --------------------
  if (phase === "write" && sameCmd) {
    if (firstParsed.nak === true) {
      retryMsg = advanceToNextCandidate(pendingLearn);
    } else if (firstParsed.ack === true) {
      if (pendingLearn.verify_required !== true) {
        saveSimpleLearn(pendingLearn);
      } else {
        setPendingLearn({
          ...pendingLearn,
          phase: "verify"
        });

        verifyMsg = buildVerifyMsg("QPIRI");

        node.status({
          fill: "yellow",
          shape: "dot",
          text: `VERIFY ${pendingLearn.param} -> ${pendingLearn.cmd}`
        });
      }
    } else if (firstParsed.raw) {
      if (pendingLearn.verify_required !== true) {
        saveSimpleLearn(pendingLearn);
      } else {
        setPendingLearn({
          ...pendingLearn,
          phase: "verify"
        });

        verifyMsg = buildVerifyMsg("QPIRI");

        node.status({
          fill: "yellow",
          shape: "dot",
          text: `VERIFY ${pendingLearn.param} -> ${pendingLearn.cmd}`
        });
      }
    }
  }

  // --------------------
  // PHASE VERIFY
  // --------------------
  else if (phase === "verify") {
    const isVerifyResponse =
      inflightCmd === "QPIRI" ||
      inflightCmd === "QDI" ||
      inflightCmd === "QFLAG" ||
      inflightCmd === "QDOP";

    if (isVerifyResponse) {
      if (firstParsed.nak === true) {
        retryMsg = advanceToNextCandidate(pendingLearn);
      } else {
        const verifiedCmd = extractVerifiedCommandFromReadback(pendingLearn, firstParsed);

        if (verifiedCmd) {
          saveMappedLearn(pendingLearn, verifiedCmd);
        } else {
          retryMsg = advanceToNextCandidate(pendingLearn);
        }
      }
    }
  }
}

// --------------------------------------------------
// libère inflight
// --------------------------------------------------
flow.set(inflightKey, null);

// --------------------------------------------------
// sortie contrôle queue
// --------------------------------------------------
const pumpMsg = { inverterNum: inv, topic: "pump" };
const ctrlMsgs = [];

if (retryMsg) ctrlMsgs.push(retryMsg);
if (verifyMsg) ctrlMsgs.push(verifyMsg);
ctrlMsgs.push(pumpMsg);

return [ctrlMsgs, outMsgs];

// ====== NORMALIZE STATE (AUTO / MULTI-MODEL) - + TZ dynamic + GRID TODAY + FULL FILTERS ======
if (!msg.payload || typeof msg.payload !== "object") return null;

const inv = msg.inverterNum ?? msg.payload.inverter ?? 1;

// Normaliser la commande (évite "QPIRI\r", "qpiri", "QPIRI ")
const cmd = String(msg.payload.command || msg.command || msg._cmd || "UNKNOWN")
  .trim()
  .toUpperCase();

const f = Array.isArray(msg.payload.fields) ? msg.payload.fields : [];
const n = Array.isArray(msg.payload.nums) ? msg.payload.nums : [];
const parsedState = (msg.payload.state && typeof msg.payload.state === "object") ? msg.payload.state : {};
const value = msg.payload.value;

let state = context.get("state");
if (!state || typeof state !== "object") state = {};

// --------------------------------------------------
// helpers de base
// --------------------------------------------------
const num = (idx) => (Number.isFinite(n[idx]) ? n[idx] : null);
const int = (idx) => {
  const v = num(idx);
  return v == null ? null : Math.trunc(v);
};
const round = (v, d) => {
  const nn = Number(v);
  if (!Number.isFinite(nn)) return null;
  const m = 10 ** d;
  return Math.round(nn * m) / m;
};
const finiteNumber = (x) => {
  const nn = Number(x);
  return Number.isFinite(nn) ? nn : null;
};
const str = (x) => String(x ?? "").trim();

// --- apprentissage index pv1_power par node (donc par inverter) ---
let pv1PowerIdx = context.get("pv1PowerIdx");

// --------------------------------------------------
// FILTRES / SANITIZE
// --------------------------------------------------
const MAX_W = 15000;
const MAX_A = 350;
const MAX_PCT = 100;

function pushSpike(entry) {
  state._spike = state._spike || [];
  state._spike.push(entry);
}

function sanitizeKeepLast(key, {
  maxAbs = null,
  allowNegative = true,
  forceNonNegative = false,
  integer = false
} = {}) {
  const raw = finiteNumber(state[key]);
  if (raw == null) return;

  let v = raw;
  if (integer) v = Math.trunc(v);
  if (forceNonNegative && v < 0) v = 0;

  const lastKey = `inv${inv}_last_ok_${key}`;
  const lastOk = flow.get(lastKey);

  if (!allowNegative && v < 0) {
    state[key] = (Number.isFinite(lastOk) ? lastOk : 0);
    pushSpike({ key, raw, reason: "negative_not_allowed" });
    return;
  }

  if (maxAbs != null && Math.abs(v) > maxAbs) {
    if (Number.isFinite(lastOk)) {
      state[key] = lastOk;
    } else {
      state[key] = forceNonNegative ? 0 : null;
    }
    pushSpike({ key, raw, maxAbs });
    return;
  }

  state[key] = v;
  flow.set(lastKey, v);
}

function sanitizePct(key) {
  const raw = finiteNumber(state[key]);
  if (raw == null) return;

  const v = Math.trunc(raw);
  const lastKey = `inv${inv}_last_ok_${key}`;
  const lastOk = flow.get(lastKey);

  if (v < 0 || v > MAX_PCT) {
    state[key] = Number.isFinite(lastOk) ? lastOk : null;
    pushSpike({ key, raw, min: 0, max: MAX_PCT });
    return;
  }

  state[key] = v;
  flow.set(lastKey, v);
}

function sanitizeAmp(key, { allowNegative = false } = {}) {
  sanitizeKeepLast(key, {
    maxAbs: MAX_A,
    allowNegative,
    forceNonNegative: !allowNegative,
    integer: false
  });
}

function sanitizeW(key, { allowNegative = false } = {}) {
  sanitizeKeepLast(key, {
    maxAbs: MAX_W,
    allowNegative,
    forceNonNegative: !allowNegative,
    integer: false
  });
}

// --------------------------------------------------
// decode fallback (si parser.state absent)
// --------------------------------------------------
function decodeBatteryType(codeRaw) {
  const code = str(codeRaw);
  const map = {
    "0": "AGM",
    "00": "AGM",
    "1": "Flooded",
    "01": "Flooded",
    "2": "User",
    "02": "User",
    "3": "Pylon",
    "03": "Pylon",
    "5": "Weco",
    "05": "Weco",
    "6": "Soltaro",
    "06": "Soltaro",
    "8": "Lib",
    "08": "Lib",
    "9": "Lic",
    "09": "Lic"
  };
  return map[code] || (code || null);
}

function decodeOutputPriority(codeRaw) {
  const code = str(codeRaw);
  const map = {
    "0": "UtilitySolarBat",
    "00": "UtilitySolarBat",
    "1": "SolarUtilityBat",
    "01": "SolarUtilityBat",
    "2": "SolarBatUtility",
    "02": "SolarBatUtility"
  };
  return map[code] || (code || null);
}

function decodeChargerPriority(codeRaw) {
  const code = str(codeRaw);
  const map = {
    "0": "Solar first",
    "00": "Solar first",
    "1": "Solar + Utility",
    "01": "Solar + Utility",
    "2": "Only solar",
    "02": "Only solar",
    // fallback firmwares 1/2/3
    "3": "Only solar",
    "03": "Only solar"
  };
  return map[code] || (code || null);
}

// --------------------------------------------------
// ===== QPIGS =====
// --------------------------------------------------
if (cmd === "QPIGS" && f.length >= 16) {
  if (f.length > 0) state.grid_voltage = round(num(0), 1);
  if (f.length > 1) state.grid_frequency = round(num(1), 1);
  if (f.length > 2) state.ac_output_voltage = round(num(2), 1);
  if (f.length > 3) state.ac_output_frequency = round(num(3), 1);

  if (f.length > 4) state.ac_output_apparent_power = int(4);
  if (f.length > 5) state.ac_output_active_power = int(5);
  if (f.length > 6) state.output_load_percent = int(6);

  if (f.length > 7) state.bus_voltage = int(7);

  if (f.length > 8) state.battery_voltage = round(num(8), 2);
  if (f.length > 9) state.battery_charging_current = round(num(9), 1);
  if (f.length > 10) state.battery_capacity = int(10);
  if (f.length > 11) state.inverter_heat_sink_temp = int(11);

  if (f.length > 12) state.pv1_input_current = round(num(12), 1);
  if (f.length > 13) state.pv1_input_voltage = round(num(13), 1);

  if (f.length > 14) state.battery_voltage_from_scc = round(num(14), 2);
  if (f.length > 15) state.battery_discharge_current = round(num(15), 1);

  const IchgA = Number.isFinite(state.battery_charging_current) ? state.battery_charging_current : 0;
  const IdisA = Number.isFinite(state.battery_discharge_current) ? state.battery_discharge_current : 0;
  state.global_current = round(IchgA - IdisA, 1);

  const Vac = Number.isFinite(state.ac_output_voltage) ? state.ac_output_voltage : null;
  const Pac = Number.isFinite(state.ac_output_active_power) ? state.ac_output_active_power : null;
  if (Vac != null && Vac > 1 && Pac != null) {
    state.inverter_output_current = round(Pac / Vac, 1);
  } else {
    state.inverter_output_current = null;
  }

  if (pv1PowerIdx != null && f.length > pv1PowerIdx) {
    state.pv1_power = int(pv1PowerIdx);
  } else {
    const candidates = [19, 20, 18, 17, 16];
    for (const idx of candidates) {
      if (f.length > idx && Number.isFinite(n[idx])) {
        const I = state.pv1_input_current;
        const V = state.pv1_input_voltage;
        const pCalc = (Number.isFinite(I) && Number.isFinite(V)) ? (I * V) : null;
        const pField = n[idx];

        if (pCalc != null && pCalc > 10) {
          const ratio = pField / pCalc;
          if (ratio > 0.8 && ratio < 1.2) {
            pv1PowerIdx = idx;
            context.set("pv1PowerIdx", pv1PowerIdx);
            state.pv1_power = int(idx);
            break;
          }
        } else {
          if (idx === 19) {
            state.pv1_power = int(19);
            break;
          }
        }
      }
    }
  }

  // GRID POWER (champ 25 firmware récents)
  if (f.length > 24 && Number.isFinite(n[24])) {
    state.grid_power = int(24);
  }

  state._last_qpigs_ts = Date.now();
}

// --------------------------------------------------
// ===== QPIGS2 (optionnel) =====
// --------------------------------------------------
if (cmd === "QPIGS2" && f.length >= 3) {
  state.pv2_input_current = round(num(0), 1);
  state.pv2_input_voltage = round(num(1), 1);
  state.pv2_power = int(2);
  state._last_qpigs2_ts = Date.now();
}

// --------------------------------------------------
// ===== QMOD =====
// --------------------------------------------------
if (cmd === "QMOD") {
  const rawMode = (f[0] ?? msg.payload.raw ?? "").toString().trim();
  const modeMap = { P: "Power On", S: "Standby", L: "Grid", B: "Battery", F: "Fault" };
  state.operation_mode = modeMap[rawMode] || rawMode || null;
  state.operation_mode_code = rawMode || null;
  state._last_qmod_ts = Date.now();
}

// --------------------------------------------------
// ===== QPIRI -> PARAMETRES =====
// priorité à msg.payload.state si dispo
// --------------------------------------------------
if (cmd === "QPIRI" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  if (!state.params || typeof state.params !== "object") state.params = {};

  const battTypeCode = parsedState.battery_type_code ?? nf(12);
  const outPrioCode = parsedState.output_source_priority_code ?? nf(16);
  const chgPrioCode = parsedState.charger_source_priority_code ?? nf(17);

  state.params.qpiri = {
    battery_recharge_voltage: nf(8),
    battery_under_voltage: nf(9),
    battery_bulk_voltage: nf(10),
    battery_float_voltage: nf(11),

    battery_type_code: battTypeCode,
    battery_type: parsedState.battery_type || decodeBatteryType(battTypeCode),

    max_ac_charging_current: parsedState.max_ac_charging_current ?? nf(13),
    max_charging_current: parsedState.max_charging_current ?? nf(14),

    output_source_priority_code: outPrioCode,
    output_source_priority: parsedState.output_source_priority || decodeOutputPriority(outPrioCode),

    charger_source_priority_code: chgPrioCode,
    charger_source_priority: parsedState.charger_source_priority || decodeChargerPriority(chgPrioCode),

    battery_re_discharge_voltage: parsedState.battery_re_discharge_voltage ?? nf(22),
    max_discharging_current: nf(27),

    ts: Date.now()
  };

  state._last_qpiri_ts = Date.now();
}

// --------------------------------------------------
// ===== QDI -> PARAMETRES (fallback / complément)
// --------------------------------------------------
if (cmd === "QDI" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  if (!state.params || typeof state.params !== "object") state.params = {};
  if (!state.params.qpiri || typeof state.params.qpiri !== "object") state.params.qpiri = {};

  const battTypeCode = parsedState.battery_type_code ?? nf(12);
  const outPrioCode = parsedState.output_source_priority_code ?? nf(16);
  const chgPrioCode = parsedState.charger_source_priority_code ?? nf(17);

  Object.assign(state.params.qpiri, {
    battery_type_code: battTypeCode ?? state.params.qpiri.battery_type_code ?? null,
    battery_type: parsedState.battery_type || decodeBatteryType(battTypeCode) || state.params.qpiri.battery_type || null,

    max_ac_charging_current: parsedState.max_ac_charging_current ?? nf(13) ?? state.params.qpiri.max_ac_charging_current ?? null,
    max_charging_current: parsedState.max_charging_current ?? nf(14) ?? state.params.qpiri.max_charging_current ?? null,

    output_source_priority_code: outPrioCode ?? state.params.qpiri.output_source_priority_code ?? null,
    output_source_priority: parsedState.output_source_priority || decodeOutputPriority(outPrioCode) || state.params.qpiri.output_source_priority || null,

    charger_source_priority_code: chgPrioCode ?? state.params.qpiri.charger_source_priority_code ?? null,
    charger_source_priority: parsedState.charger_source_priority || decodeChargerPriority(chgPrioCode) || state.params.qpiri.charger_source_priority || null,

    battery_re_discharge_voltage: parsedState.battery_re_discharge_voltage ?? nf(22) ?? state.params.qpiri.battery_re_discharge_voltage ?? null,
    ts: Date.now()
  });

  state._last_qdi_ts = Date.now();
}

// --------------------------------------------------
// ===== QDOP -> PARAMETRES batterie (%) =====
// --------------------------------------------------
if (cmd === "QDOP" && msg.payload?.nak !== true) {
  const nf = (idx) => {
    const v = (f && f.length > idx) ? f[idx] : null;
    const nn = Number(v);
    return Number.isFinite(nn) ? nn : null;
  };

  if (!state.params || typeof state.params !== "object") state.params = {};

  state.params.qdop = {
    battery_recharge_capacity_pct: nf(8),
    battery_redischarge_capacity_pct: nf(9),
    battery_under_capacity_pct: nf(10),
    ts: Date.now()
  };

  state._last_qdop_ts = Date.now();
}

// --------------------------------------------------
// ===== DIAGNOSTIC (model/serial/fw + faults/warnings) =====
// --------------------------------------------------
if (cmd === "QMN" && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  state.diag.model = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  state._last_qmn_ts = Date.now();
}

if ((cmd === "QID" || cmd === "QSID") && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  state.diag.serial = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  state._last_qid_ts = Date.now();
}

if ((cmd === "QVFW" || cmd === "QVFW3") && msg.payload?.nak !== true) {
  state.diag = state.diag || {};
  const fw = (f[0] ?? msg.payload.raw ?? "").toString().trim() || null;
  if (cmd === "QVFW") state.diag.fw_main = fw;
  if (cmd === "QVFW3") state.diag.fw_remote = fw;
  state._last_qvfw_ts = Date.now();
}

// --------------------------------------------------
// ===== QPIWS -> FAULTS / WARNINGS =====
// --------------------------------------------------
if (cmd === "QPIWS" && msg.payload?.nak !== true) {
  const bits = String(f[0] ?? msg.payload.raw ?? "").trim();
  if (!state.diag || typeof state.diag !== "object") state.diag = {};

  const bit = (i) => (bits.length > i ? bits.charAt(i) === "1" : false);
  const a1_fault = bit(1);

  const map = [
    { i: 0, label: "PV loss", kind: "warn" },
    { i: 1, label: "Inverter fault", kind: "fault" },
    { i: 2, label: "Bus over", kind: "fault" },
    { i: 3, label: "Bus under", kind: "fault" },
    { i: 4, label: "Bus soft fail", kind: "fault" },
    { i: 5, label: "Line fail", kind: "warn" },
    { i: 6, label: "OPV short", kind: "fault" },
    { i: 7, label: "Inverter voltage low", kind: "fault" },
    { i: 8, label: "Inverter voltage high", kind: "fault" },
    { i: 9, label: "Over temperature", kind: () => a1_fault ? "fault" : "warn" },
    { i: 10, label: "Fan locked", kind: () => a1_fault ? "fault" : "warn" },
    { i: 11, label: "Battery voltage high", kind: () => a1_fault ? "fault" : "warn" },
    { i: 12, label: "Battery low alarm", kind: "warn" },
    { i: 14, label: "Battery shutdown", kind: "warn" },
    { i: 15, label: "Battery derating", kind: "warn" },
    { i: 16, label: "Over load", kind: () => a1_fault ? "fault" : "warn" },
    { i: 17, label: "EEPROM fault", kind: "warn" },
    { i: 18, label: "Inverter over current", kind: "fault" },
    { i: 19, label: "Inverter soft fail", kind: "fault" },
    { i: 20, label: "Self test fail", kind: "fault" },
    { i: 21, label: "OP DC voltage over", kind: "fault" },
    { i: 23, label: "Current sensor fail", kind: "fault" },
    { i: 33, label: "Low PV energy", kind: "warn" },
    { i: 34, label: "High AC input", kind: "warn" },
    { i: 35, label: "Battery equalization", kind: "warn" }
  ];

  const faults = [];
  const warns = [];

  for (const m of map) {
    if (!bit(m.i)) continue;
    const k = (typeof m.kind === "function") ? m.kind() : m.kind;
    if (k === "fault") faults.push(m.label);
    else warns.push(m.label);
  }

  state.diag.fault_state = faults.length ? "FAULT" : "OK";
  state.diag.fault_details = faults.length ? faults.join(", ") : "None";
  state.diag.warn_state = warns.length ? "WARN" : "OK";
  state.diag.warn_details = warns.length ? warns.join(", ") : "None";
  state.diag.has_fault = faults.length > 0;
  state.diag.has_warning = warns.length > 0;
  state.diag._last_qpiws_ts = Date.now();
}

// --------------------------------------------------
// ===== Support QPIGS2 =====
// --------------------------------------------------
const supportsKey = `inv${inv}_supports_qpigs2`;
const supports = flow.get(supportsKey);
if (supports !== undefined) state.supports_qpigs2 = (supports !== false);

// --------------------------------------------------
// ===== ENERGIES =====
// --------------------------------------------------
const round2 = (v) => (v == null ? null : Math.round(v * 100) / 100);
const toKwhToday = (v) => (!Number.isFinite(v) ? null : round2(v / 1000));
const toKwhAuto = (v) => (!Number.isFinite(v) ? null : (v >= 10000 ? round2(v / 1000) : round2(v)));

if (Number.isFinite(value)) {
  if (cmd === "QET") { state.pv_energy_total_raw = value; state.pv_energy_total_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QEY")) { state.pv_energy_year_raw = value; state.pv_energy_year_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QEM")) { state.pv_energy_month_raw = value; state.pv_energy_month_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QED")) { state.pv_energy_day_raw = value; state.pv_energy_day_kwh = toKwhToday(value); }

  if (cmd === "QLT") { state.load_energy_total_raw = value; state.load_energy_total_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLY")) { state.load_energy_year_raw = value; state.load_energy_year_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLM")) { state.load_energy_month_raw = value; state.load_energy_month_kwh = toKwhAuto(value); }
  if (cmd.startsWith("QLD")) { state.load_energy_day_raw = value; state.load_energy_day_kwh = toKwhToday(value); }

  state._last_energy_ts = Date.now();
}

// --------------------------------------------------
// ===== PV total power =====
// --------------------------------------------------
const pv1 = Number.isFinite(state.pv1_power) ? state.pv1_power : 0;
const pv2 = Number.isFinite(state.pv2_power) ? state.pv2_power : 0;
state.pv_total_power = pv1 + pv2;

// --------------------------------------------------
// ===== BATTERY POWER (W) =====
// --------------------------------------------------
const Vb = Number.isFinite(state.battery_voltage) ? state.battery_voltage : null;
const Ichg = Number.isFinite(state.battery_charging_current) ? state.battery_charging_current : 0;
const Idis = Number.isFinite(state.battery_discharge_current) ? state.battery_discharge_current : 0;

if (Vb != null) {
  const chargeW = round(Vb * Math.max(0, Ichg), 1);
  const dischargeW = round(Vb * Math.max(0, Idis), 1);

  state.battery_charge = chargeW;
  state.battery_discharge = dischargeW;
  state.battery_power = (chargeW != null && dischargeW != null) ? round(chargeW - dischargeW, 1) : null;
} else {
  state.battery_charge = null;
  state.battery_discharge = null;
  state.battery_power = null;
}

// --------------------------------------------------
// ===== TIMEZONE dayKey (dynamic) =====
// --------------------------------------------------
function localDayKey(d = new Date()) {
  let tz = (global.get("addon_timezone") || "UTC").toString().trim();
  if (!tz) tz = "UTC";
  try {
    new Intl.DateTimeFormat("en-CA", { timeZone: tz }).format(new Date());
  } catch (e) {
    tz = "UTC";
  }

  const parts = new Intl.DateTimeFormat("en-CA", {
    timeZone: tz,
    year: "numeric",
    month: "2-digit",
    day: "2-digit"
  }).formatToParts(d);

  const get = (t) => parts.find(p => p.type === t)?.value;
  return `${get("year")}${get("month")}${get("day")}`;
}

const dayKey = localDayKey(new Date());

// --------------------------------------------------
// ===== DAILY ENERGY (kWh) - Battery charge/discharge today =====
// --------------------------------------------------
const kDay = `inv${inv}_batt_dayKey`;
const kTs = `inv${inv}_batt_lastTs`;
const kChg = `inv${inv}_batt_lastChargeW`;
const kDis = `inv${inv}_batt_lastDischargeW`;
const kChgWh = `inv${inv}_batt_chargeWh_today`;
const kDisWh = `inv${inv}_batt_dischargeWh_today`;

const lastDay = flow.get(kDay);
let lastTs = flow.get(kTs);
let lastChargeW = flow.get(kChg);
let lastDischargeW = flow.get(kDis);

let chargeWh = flow.get(kChgWh);
let dischargeWh = flow.get(kDisWh);

if (!Number.isFinite(chargeWh)) chargeWh = 0;
if (!Number.isFinite(dischargeWh)) dischargeWh = 0;

if (lastDay && lastDay !== dayKey) {
  chargeWh = 0;
  dischargeWh = 0;
}

const curChargeW = Number.isFinite(state.battery_charge) ? state.battery_charge : 0;
const curDischargeW = Number.isFinite(state.battery_discharge) ? state.battery_discharge : 0;

const nowTs = Date.now();

if (Number.isFinite(lastTs) && Number.isFinite(lastChargeW) && Number.isFinite(lastDischargeW)) {
  const dtMs = nowTs - lastTs;
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;
    chargeWh += ((lastChargeW + curChargeW) / 2) * dtH;
    dischargeWh += ((lastDischargeW + curDischargeW) / 2) * dtH;
  }
}

flow.set(kDay, dayKey);
flow.set(kTs, nowTs);
flow.set(kChg, curChargeW);
flow.set(kDis, curDischargeW);
flow.set(kChgWh, chargeWh);
flow.set(kDisWh, dischargeWh);

state.battery_charge_day_kwh = Math.round((chargeWh / 1000) * 100) / 100;
state.battery_discharge_day_kwh = Math.round((dischargeWh / 1000) * 100) / 100;
state._day_key = dayKey;

// --------------------------------------------------
// ===== GRID TODAY (kWh) - from grid_power (W) =====
// --------------------------------------------------
const kGDay = `inv${inv}_grid_dayKey`;
const kGTs = `inv${inv}_grid_lastTs`;
const kGLastW = `inv${inv}_grid_lastW`;
const kGWh = `inv${inv}_grid_Wh_today`;

let gLastDay = flow.get(kGDay);
let gLastTs = flow.get(kGTs);
let gLastW = flow.get(kGLastW);
let gWh = flow.get(kGWh);

if (!Number.isFinite(gWh)) gWh = 0;

if (gLastDay && gLastDay !== dayKey) {
  gWh = 0;
}

const gCurW_raw = Number.isFinite(state.grid_power) ? state.grid_power : 0;
const gCurW = Math.max(0, gCurW_raw);

const gNowTs = Date.now();

if (Number.isFinite(gLastTs) && Number.isFinite(gLastW)) {
  const dtMs = gNowTs - gLastTs;
  if (dtMs > 0 && dtMs <= 10 * 60 * 1000) {
    const dtH = dtMs / 3600000;
    gWh += ((gLastW + gCurW) / 2) * dtH;
  }
}

flow.set(kGDay, dayKey);
flow.set(kGTs, gNowTs);
flow.set(kGLastW, gCurW);
flow.set(kGWh, gWh);

state.grid_energy_day_kwh = Math.round((gWh / 1000) * 100) / 100;

// --------------------------------------------------
// ===== FILTRES GLOBAUX FINAL =====
// --------------------------------------------------
sanitizeW("ac_output_apparent_power", { allowNegative: false });
sanitizeW("ac_output_active_power", { allowNegative: false });
sanitizeW("pv1_power", { allowNegative: false });
sanitizeW("pv2_power", { allowNegative: false });
sanitizeW("pv_total_power", { allowNegative: false });
sanitizeW("grid_power", { allowNegative: true });
sanitizeW("battery_charge", { allowNegative: false });
sanitizeW("battery_discharge", { allowNegative: false });
sanitizeW("battery_power", { allowNegative: true });

sanitizeAmp("battery_charging_current", { allowNegative: false });
sanitizeAmp("battery_discharge_current", { allowNegative: false });
sanitizeAmp("pv1_input_current", { allowNegative: false });
sanitizeAmp("pv2_input_current", { allowNegative: false });
sanitizeAmp("global_current", { allowNegative: true });
sanitizeAmp("inverter_output_current", { allowNegative: false });

sanitizePct("battery_capacity");
sanitizePct("output_load_percent");

if (state.params?.qdop) {
  const qdop = state.params.qdop;

  const sanitizeNestedPct = (obj, key) => {
    const raw = finiteNumber(obj[key]);
    if (raw == null) return;

    const v = Math.trunc(raw);
    const lastKey = `inv${inv}_last_ok_params_qdop_${key}`;
    const lastOk = flow.get(lastKey);

    if (v < 0 || v > MAX_PCT) {
      obj[key] = Number.isFinite(lastOk) ? lastOk : null;
      pushSpike({ key: `params.qdop.${key}`, raw, min: 0, max: MAX_PCT });
      return;
    }

    obj[key] = v;
    flow.set(lastKey, v);
  };

  sanitizeNestedPct(qdop, "battery_recharge_capacity_pct");
  sanitizeNestedPct(qdop, "battery_redischarge_capacity_pct");
  sanitizeNestedPct(qdop, "battery_under_capacity_pct");
}

if (state.params?.qpiri) {
  const qpiri = state.params.qpiri;

  const sanitizeNestedAmp = (obj, key, { allowNegative = false } = {}) => {
    const raw = finiteNumber(obj[key]);
    if (raw == null) return;

    let v = raw;
    if (!allowNegative && v < 0) {
      const lastKey = `inv${inv}_last_ok_params_qpiri_${key}`;
      const lastOk = flow.get(lastKey);
      obj[key] = Number.isFinite(lastOk) ? lastOk : 0;
      pushSpike({ key: `params.qpiri.${key}`, raw, reason: "negative_not_allowed" });
      return;
    }

    if (Math.abs(v) > MAX_A) {
      const lastKey = `inv${inv}_last_ok_params_qpiri_${key}`;
      const lastOk = flow.get(lastKey);
      obj[key] = Number.isFinite(lastOk) ? lastOk : null;
      pushSpike({ key: `params.qpiri.${key}`, raw, maxAbs: MAX_A });
      return;
    }

    obj[key] = v;
    flow.set(`inv${inv}_last_ok_params_qpiri_${key}`, v);
  };

  sanitizeNestedAmp(qpiri, "max_ac_charging_current", { allowNegative: false });
  sanitizeNestedAmp(qpiri, "max_charging_current", { allowNegative: false });
  sanitizeNestedAmp(qpiri, "max_discharging_current", { allowNegative: false });

  if (Number.isFinite(qpiri.output_source_priority_code)) {
    const c = Math.trunc(qpiri.output_source_priority_code);
    if (c < 0 || c > 3) {
      pushSpike({ key: "params.qpiri.output_source_priority_code", raw: qpiri.output_source_priority_code, min: 0, max: 3 });
      qpiri.output_source_priority_code = null;
    } else {
      qpiri.output_source_priority_code = c;
    }
  }

  if (Number.isFinite(qpiri.charger_source_priority_code)) {
    const c = Math.trunc(qpiri.charger_source_priority_code);
    if (c < 0 || c > 3) {
      pushSpike({ key: "params.qpiri.charger_source_priority_code", raw: qpiri.charger_source_priority_code, min: 0, max: 3 });
      qpiri.charger_source_priority_code = null;
    } else {
      qpiri.charger_source_priority_code = c;
    }
  }

  if (Number.isFinite(qpiri.battery_type_code)) {
    const c = Math.trunc(qpiri.battery_type_code);
    if (c < 0 || c > 9) {
      pushSpike({ key: "params.qpiri.battery_type_code", raw: qpiri.battery_type_code, min: 0, max: 9 });
      qpiri.battery_type_code = null;
    } else {
      qpiri.battery_type_code = c;
    }
  }
}

// --------------------------------------------------
// pratique : remonter certains paramètres au niveau racine
// --------------------------------------------------
if (state.params?.qpiri) {
  state.battery_type = state.params.qpiri.battery_type ?? state.battery_type ?? null;
  state.output_source_priority = state.params.qpiri.output_source_priority ?? state.output_source_priority ?? null;
  state.charger_source_priority = state.params.qpiri.charger_source_priority ?? state.charger_source_priority ?? null;
}

// --------------------------------------------------
// persist
// --------------------------------------------------
context.set("state", state);
msg.inverterNum = inv;
msg.payload = state;
return msg;

// ===============================
// MQTT STATE PUBLISHER (STABLE JSON)
// + DISPLAY MODE ADAPTATION
// ===============================

if (!msg.payload || typeof msg.payload !== "object") return null;

const inv = msg.inverterNum ?? 1;
const data = JSON.parse(JSON.stringify(msg.payload));

const displayMode =
    global.get(`inverter_${inv}.display_mode`) || "modern";

// -------------------------------------------------
// Helpers
// -------------------------------------------------
const ensure = (obj, key, value = null) => {
    if (obj[key] === undefined) obj[key] = value;
};

// -------------------------------------------------
// DISPLAY MODE CONVERSION
// -------------------------------------------------
function mapOutputPriority(v) {
    if (!v) return v;

    if (displayMode === "legacy_usb_sub_sbu") {
        const map = {
            UtilitySolarBat: "USB",
            SolarUtilityBat: "SUB",
            SolarBatUtility: "SBU"
        };
        return map[v] || v;
    }

    if (displayMode === "legacy_uti_sol_sbu") {
        const map = {
            UtilitySolarBat: "UTI",
            SolarUtilityBat: "SOL",
            SolarBatUtility: "SBU"
        };
        return map[v] || v;
    }

    return v;
}

function mapChargerPriority(v) {
    if (!v) return v;

    if (displayMode !== "modern") {
        const map = {
            "Solar first": "CSO",
            "Solar + Utility": "SNU",
            "Only solar": "OSO"
        };
        return map[v] || v;
    }

    return v;
}

// -------------------------------------------------
// APPLY DISPLAY MODE
// -------------------------------------------------
if (data.params?.qpiri) {
    data.params.qpiri.output_source_priority =
        mapOutputPriority(data.params.qpiri.output_source_priority);

    data.params.qpiri.charger_source_priority =
        mapChargerPriority(data.params.qpiri.charger_source_priority);
}

// pratique aussi au niveau racine si présent
if (data.output_source_priority !== undefined) {
    data.output_source_priority = mapOutputPriority(data.output_source_priority);
}

if (data.charger_source_priority !== undefined) {
    data.charger_source_priority = mapChargerPriority(data.charger_source_priority);
}

// -------------------------------------------------
// 1) STRUCTURE PRINCIPALE
// -------------------------------------------------
ensure(data, "grid_voltage");
ensure(data, "grid_frequency");
ensure(data, "ac_output_voltage");
ensure(data, "ac_output_frequency");
ensure(data, "ac_output_active_power");
ensure(data, "output_load_percent");

ensure(data, "battery_voltage");
ensure(data, "battery_charging_current");
ensure(data, "battery_discharge_current");
ensure(data, "battery_capacity");

ensure(data, "battery_charge");
ensure(data, "battery_discharge");
ensure(data, "battery_power");

ensure(data, "pv_total_power");
ensure(data, "pv1_power");
ensure(data, "pv2_power");

ensure(data, "pv1_input_voltage");
ensure(data, "pv2_input_voltage");
ensure(data, "pv1_input_current");
ensure(data, "pv2_input_current");

ensure(data, "grid_power");
ensure(data, "inverter_heat_sink_temp");

ensure(data, "operation_mode");

// -------------------------------------------------
// 2) ENERGIES
// -------------------------------------------------
ensure(data, "load_energy_month_kwh");
ensure(data, "load_energy_year_kwh");
ensure(data, "load_energy_day_kwh");
ensure(data, "load_energy_total_kwh");

ensure(data, "pv_energy_month_kwh");
ensure(data, "pv_energy_year_kwh");
ensure(data, "pv_energy_day_kwh");
ensure(data, "pv_energy_total_kwh");

// -------------------------------------------------
// 3) DIAG
// -------------------------------------------------
if (!data.diag) data.diag = {};

ensure(data.diag, "model", "unknown");
ensure(data.diag, "serial", "unknown");
ensure(data.diag, "fw_main", "unknown");
ensure(data.diag, "fw_remote", "unknown");
ensure(data.diag, "fault_state", "unknown");
ensure(data.diag, "fault_details", "unknown");
ensure(data.diag, "warn_state", "unknown");
ensure(data.diag, "warn_details", "unknown");

// -------------------------------------------------
// 4) PARAMS
// -------------------------------------------------
if (!data.params) data.params = {};
if (!data.params.qpiri) data.params.qpiri = {};
if (!data.params.qdop) data.params.qdop = {};

const qpiri = data.params.qpiri;
const qdop = data.params.qdop;

ensure(qpiri, "battery_type");
ensure(qpiri, "output_source_priority");
ensure(qpiri, "charger_source_priority");

ensure(qpiri, "battery_bulk_voltage");
ensure(qpiri, "battery_float_voltage");
ensure(qpiri, "battery_re_discharge_voltage");
ensure(qpiri, "battery_recharge_voltage");
ensure(qpiri, "battery_under_voltage");

ensure(qpiri, "max_ac_charging_current");
ensure(qpiri, "max_charging_current");
ensure(qpiri, "max_discharging_current");

ensure(qdop, "battery_recharge_capacity_pct");
ensure(qdop, "battery_redischarge_capacity_pct");
ensure(qdop, "battery_under_capacity_pct");

// -------------------------------------------------
// 5) PUBLISH MQTT
// -------------------------------------------------
return [
    {
        topic: `voltronic/${inv}/state`,
        payload: JSON.stringify(data),
        retain: true
    },
    {
        topic: `voltronic/${inv}/availability`,
        payload: "online",
        retain: true
    }
];

const inv = msg.inverterNum ?? 1;
const key = `inv${inv}_queue`;
const inFlightKey = `inv${inv}_inflight`;

let q = flow.get(key);
if (!Array.isArray(q)) q = [];

const inFlight = flow.get(inFlightKey);

// msg peut être 1 commande, ou un lot
const toPush = [];

if (Array.isArray(msg)) {
    toPush.push(...msg);
} else if (Array.isArray(msg.payload) && msg.payload?.[0]?.command) {
    toPush.push(...msg.payload);
} else {
    toPush.push(msg);
}

const now = Date.now();

function getQpigs2State() {
    const qpKey = `inv${inv}_qpigs2_state`;
    let st = flow.get(qpKey);

    if (!st || typeof st !== "object") {
        st = {
            fail_count: 0,
            disabled: false,
            last_try: 0,
            last_ok: 0,
            last_fail: 0,
            reason: ""
        };
        flow.set(qpKey, st);
    }

    return st;
}

// normalise
function normalizeCmd(m) {
    const cmd = (m.command || m._cmd || m.payload || "").toString().trim().toUpperCase();
    if (!cmd) return null;

    return {
        inverterNum: m.inverterNum ?? inv,
        command: cmd,
        _cmd: cmd,
        payload: cmd,
        _burst: !!m._burst,
        _origin: m._origin || "",
        _learn: m._learn || null,
        _qpigs2_probe: !!m._qpigs2_probe,
        enqueued_ts: now
    };
}

for (const m of toPush) {
    const item = normalizeCmd(m);
    if (!item) continue;

    const isPriority =
        item._origin === "ha_set" ||
        item._origin === "learn_retry";

    const cmd = item.command;

    // -------------------------------------------------
    // règle spéciale QPIGS2
    // si désactivé, on bloque sauf si c'est un probe explicite
    // -------------------------------------------------
    if (cmd === "QPIGS2") {
        const st = getQpigs2State();

        if (st.disabled && item._qpigs2_probe !== true) {
            continue;
        }
    }

    // -------------------------------------------------
    // anti-doublon queue
    // -------------------------------------------------
    const alreadyQueued = q.some(x => x && x.command === cmd);

    // -------------------------------------------------
    // anti-doublon inflight
    // -------------------------------------------------
    const alreadyInFlight =
        inFlight &&
        String(inFlight.cmd || "").trim().toUpperCase() === cmd;

    // priorité :
    // - ha_set / learn_retry passent quand même
    // - sinon on évite doublons queue + inflight
    if (!isPriority) {
        if (alreadyQueued || alreadyInFlight) {
            continue;
        }
    }

    if (isPriority) {
        q.unshift(item);
    } else {
        q.push(item);
    }
}

// limite taille
if (q.length > 200) {
    q = q.slice(0, 200);
}

flow.set(key, q);

// déclenche le pump
node.status({
    fill: "blue",
    shape: "dot",
    text: `queue: ${q.length}`
});

return { inverterNum: inv, topic: "pump" };

// HA SET -> Voltronic CMD  (1 sortie)
// topic: voltronic/<inv>/set/<param>
// payload: valeur

const m = (msg.topic || "").match(/^voltronic\/(\d+)\/set\/(.+)$/);
if (!m) return null;

const inverterNum = Number(m[1]);
let param = String(m[2] || "").trim();

// --------------------
// Alias paramètres
// --------------------
if (param === "charging_priority") param = "charger_source_priority";

// --------------------
// Normalisation payload
// --------------------
let v = msg.payload;

if (typeof v === "string") {
  v = v.trim();
  v = v.replace(/^"+|"+$/g, "");

  try {
    if (v.startsWith('\\"') || (v.startsWith('"') && v.endsWith('"'))) {
      v = JSON.parse(v);
    }
  } catch (e) {
    // ignore
  }

  if (typeof v === "string") {
    v = v.trim().replace(/^"+|"+$/g, "");
  }
}

// --------------------
// Helpers
// --------------------
const toNum = (x) => {
  if (x == null) return null;

  if (typeof x === "string") {
    const s = x.trim().replace(/^"+|"+$/g, "");
    const m = s.match(/-?\d+(\.\d+)?/);
    if (!m) return null;
    x = m[0];
  }

  const n = Number(x);
  return Number.isFinite(n) ? n : null;
};

const pad2 = (x) => String(Math.trunc(Number(x))).padStart(2, "0");
const pad3 = (x) => String(Math.trunc(Number(x))).padStart(3, "0");
const fixed1 = (x) => Number(x).toFixed(1);
const clamp = (x, a, b) => Math.min(b, Math.max(a, Number(x)));
const uniq = (arr) => [...new Set((arr || []).filter(Boolean))];

const normStr = (x) =>
  String(x ?? "")
    .trim()
    .replace(/^"+|"+$/g, "");

const normKey = (x) => normStr(x).toUpperCase();

// --------------------
// Traduction HA -> interne
