// --------------------
// Builders
// --------------------
const mk = (c, extra = {}) => ({
  inverterNum,
  command: c,
  _cmd: c,
  payload: c,
  _burst: true,
  ...extra
});

function getLearnedLabel(paramName) {
  const entry = learned[paramName];
  if (entry && typeof entry === "object" && entry.label) return entry.label;
  return null;
}

function getLearnedMappedCommand(paramName, valueKey) {
  const entry = learned[paramName];
  if (entry && typeof entry === "object" && entry.map && entry.map[valueKey]) {
    return entry.map[valueKey];
  }
  return null;
}

function setPendingLearn(data) {
  flow.set(`learn_pending_inv${inverterNum}`, {
    inverterNum,
    ts: Date.now(),
    ...data
  });
}

function buildCandidatesFromVariants(paramName, rawValue, variants) {
  const learnedLabel = getLearnedLabel(paramName);
  let out = [];

  if (learnedLabel) {
    const learnedVariant = variants.find(x => x.label === learnedLabel);
    if (learnedVariant) {
      const c = learnedVariant.build(rawValue);
      if (c) out.push(c);
    }
  }

  for (const variant of variants) {
    const c = variant.build(rawValue);
    if (c) out.push(c);
  }

  return uniq(out);
}

