function buildPcpCandidates(valueKey) {
  const sv = normStr(valueKey);

  const learnedCmd = getLearnedMappedCommand("charger_source_priority", sv);
  if (learnedCmd) return [learnedCmd];

  // Base la plus fréquente
  const map0 = {
    "Solar first": "PCP00",
    "Solar + Utility": "PCP01",
    "Only solar": "PCP02"
  };

  // Fallback pour certains firmwares
  const map1 = {
    "Solar first": "PCP01",
    "Solar + Utility": "PCP02",
    "Only solar": "PCP03"
  };

  return uniq([
    map0[sv] || null,
    map1[sv] || null
  ]);
}

function buildPopCandidates(valueKey) {
  const sv = normStr(valueKey);

  const learnedCmd = getLearnedMappedCommand("output_source_priority", sv);
  if (learnedCmd) return [learnedCmd];

  // Base la plus fréquente
  const map0 = {
    UtilitySolarBat: "POP00",
    SolarUtilityBat: "POP01",
    SolarBatUtility: "POP02"
  };

  // Fallback pour certains firmwares
  const map1 = {
    UtilitySolarBat: "POP01",
    SolarUtilityBat: "POP02",
    SolarBatUtility: "POP03"
  };

  return uniq([
    map0[sv] || null,
    map1[sv] || null
  ]);
}

