const BASE_TOPIC = "voltronic";

// =======================
// Display mode par onduleur
// =======================
const displayMode = String(global.get(`inverter_${inv}.display_mode`) || "modern").trim();

function getOutputPriorityOptions(mode) {
  if (mode === "legacy_usb_sub_sbu") {
    return ["USB", "SUB", "SBU"];
  }
  if (mode === "legacy_uti_sol_sbu") {
    return ["UTI", "SOL", "SBU"];
  }
  return ["UtilitySolarBat", "SolarUtilityBat", "SolarBatUtility"];
}

function getChargerPriorityOptions(mode) {
  if (mode === "modern") {
    return ["Solar first", "Solar + Utility", "Only solar"];
  }
  return ["CSO", "SNU", "OSO"];
}

const outputPriorityOptions = getOutputPriorityOptions(displayMode);
const chargerPriorityOptions = getChargerPriorityOptions(displayMode);

// defaults
const outputPriorityDefault =
  displayMode === "modern" ? "SolarBatUtility" : "SBU";

const chargerPriorityDefault =
  displayMode === "modern" ? "Solar first" : "CSO";

// =======================
// Battery system voltage (24/48)
// =======================
const sysV = Number(
  global.get("config.batterySystemVoltage") ||
  global.get("battery_system_voltage") ||
  48
);
const is24 = (sysV === 24);

const V_RANGES = is24 ? {
  bulk: { min: 24, max: 30, step: 0.1 },
  float: { min: 24, max: 30, step: 0.1 },
  returnGrid: { min: 22, max: 25.5, step: 0.5 },
  reDischarge: { min: 24, max: 29, step: 0.5 },
  under: { min: 20, max: 27, step: 0.5 },
} : {
  bulk: { min: 40, max: 65, step: 0.1 },
  float: { min: 40, max: 65, step: 0.1 },
