  textCfg("raw_command", "Raw command", raw_command_topic, {
    icon: "mdi:console",
    entity_category: "diagnostic"
  }),
];

let msgs = [];

// 1) si config changée, effacer les anciens retained
if (changed) {
  msgs = msgs.concat(clearPublishedTopics());
}

// 2) republier le discovery de cet onduleur
msgs = msgs.concat(msgsSensors, msgsParams, msgsDiag);

// 3) mémoriser
flow.set(lastSigKey, signature);
flow.set(topicsKey, publishedTopics);

return [msgs];

const inputEnv = msg.payload.toString().trim();

let configPath;
let statusColor;
let bip;

switch(inputEnv) {
    case 'HAOS':
        configPath = '/data/options.json';
        msg.environment = 'Home Assistant OS';
        bip = 1;
        statusColor = 'green';
        break;
    case 'Docker':
        configPath = '/data/options.json';
        msg.environment = 'Docker (autre)';
        bip = 2;
        statusColor = 'blue';
        break;
    case 'Linux':
        configPath = '/data/options.json';
        msg.environment = 'Linux barebone';
        bip = 3;
        statusColor = 'yellow';
        break;
    case 'Windows':
        configPath = 'C:\\data\\options.json';
        msg.environment = 'Windows';
        bip = 4;
        statusColor = 'purple';
        break;
    default:
        configPath = './data/options.json';
        msg.environment = 'Inconnu';
        bip = 5;
        statusColor = 'red';
}

msg.filename = configPath;
msg.payload = {"bip": String(bip)};
msg.headers = {
    "Content-Type": "application/json"
};
node.status({fill:statusColor, shape:"dot", text: msg.environment});
return msg;
